patches.fixed_method:
InputStream decode(final InputStream in, final Coder coder,
        byte[] password) throws IOException {
    if (coder == null || coder.properties == null || coder.properties.length < 5) {
        throw new IllegalArgumentException("Invalid coder properties");
    }
    byte propsByte = coder.properties[0];
    long dictSize = ((long) coder.properties[1] & 0xFF) |
                  (((long) coder.properties[2] & 0xFF) << 8) |
                  (((long) coder.properties[3] & 0xFF) << 16) |
                  (((long) coder.properties[4] & 0xFF) << 24);
    if (dictSize > LZMAInputStream.DICT_SIZE_MAX) {
        throw new IOException("Dictionary larger than 4GiB maximum size");
    }
    return new LZMAInputStream(in, -1, propsByte, (int) dictSize);
}

InputStream decode(final InputStream in, final Coder coder,
        byte[] password) throws IOException {
    if (coder == null || coder.properties == null) {
        throw new IllegalArgumentException("Coder and its properties cannot be null");
    }
    if (coder.properties.length < 5) {
        throw new IllegalArgumentException("Insufficient properties to decode");
    }
    byte propsByte = coder.properties[0];
    long dictSize = coder.properties[1];
    for (int i = 1; i < 4; i++) {
        dictSize |= ((coder.properties[i + 1] & 0xFFL) << (8 * i));
    }
    if (dictSize < 0 || dictSize > LZMAInputStream.DICT_SIZE_MAX) {
        throw new IOException("Dictionary size out of valid range");
    }
    return new LZMAInputStream(in, -1, propsByte, (int) dictSize);
}
